SELECT o.id, o.order_no, o.resource_id, r.name AS resourceName, t.name AS tenantName, o.booking_date, o.start_time, o.end_time, o.status FROM booking_order o LEFT JOIN booking_resource r ON o.resource_id = r.id LEFT JOIN sys_tenant t ON r.tenant_id = t.id WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC

SELECT o.id, o.order_no, o.resource_id, r.name AS resourceName, t.name AS tenantName, o.booking_date, o.start_time, o.end_time, o.status FROM booking_order o LEFT JOIN booking_resource r ON o.resource_id = r.id LEFT JOIN sys_tenant t ON r.tenant_id = t.id
AND o.status = #{status}
AND o.resource_id = #{resourceId}
ORDER BY o.create_time DESC
